use image::{GrayImage, Rgba, RgbaImage};
use std::collections::VecDeque;
use std::env;
use std::fs;
use std::path::{Path, PathBuf};
use std::time::{SystemTime, UNIX_EPOCH};

#[derive(Clone, Copy, Debug)]
struct TextSlot {
    bbox: [u32; 4],
    area: u32,
}

fn main() -> Result<(), String> {
    let args = Args::parse(env::args().skip(1).collect())?;
    fs::create_dir_all(&args.out_dir).map_err(|e| e.to_string())?;

    if args.image.is_file() {
        let mask = args
            .mask
            .as_ref()
            .ok_or_else(|| "--mask is required when --image is a file".to_string())?;
        let out = args.out_dir.join(output_name(&args.image));
        recompose_one(&args.image, mask, &out, &args.text, args.scale, args.layout)?;
        println!("recomposed={}", out.display());
        return Ok(());
    }

    let mask_dir = args
        .mask
        .as_ref()
        .ok_or_else(|| "--mask DIR is required when --image is a directory".to_string())?;
    let mut written = 0_u32;
    let mut images = collect_cleared_images(&args.image)?;
    images.sort();
    if let Some(limit) = args.limit {
        images.truncate(limit);
    }
    if args.random_ranked {
        let choice = choose_ranked_random_image(&images, mask_dir, &args)?;
        let out = args.out_dir.join(format!("{}.recomposed.png", choice.stem));
        recompose_one(
            &choice.image,
            &choice.mask,
            &out,
            &args.text,
            args.scale,
            args.layout,
        )?;
        println!("ranked_random_choice={}", choice.stem);
        println!("ranked_random_score={:.4}", choice.score);
        println!("ranked_random_slots={}", choice.slots);
        println!("recomposed={}", out.display());
        return Ok(());
    }
    for image in images {
        let Some(stem) = image
            .file_name()
            .and_then(|name| name.to_str())
            .and_then(|name| name.strip_suffix(".cleared.png"))
        else {
            continue;
        };
        let mask = mask_dir.join(format!("{stem}.text-region-mask.png"));
        if !mask.exists() {
            continue;
        }
        let out = args.out_dir.join(format!("{stem}.recomposed.png"));
        recompose_one(&image, &mask, &out, &args.text, args.scale, args.layout)?;
        written = written.saturating_add(1);
    }
    println!("recomposed_dir={}", args.out_dir.display());
    println!("recomposed_images={written}");
    Ok(())
}

fn recompose_one(
    image_path: &Path,
    mask_path: &Path,
    out_path: &Path,
    text: &str,
    scale_override: Option<u32>,
    layout: LayoutMode,
) -> Result<(), String> {
    let mut image = image::open(image_path)
        .map_err(|e| format!("image decode {}: {e}", image_path.display()))?
        .to_rgba8();
    let mask = image::open(mask_path)
        .map_err(|e| format!("mask decode {}: {e}", mask_path.display()))?
        .to_luma8();
    if image.dimensions() != mask.dimensions() {
        return Err(format!(
            "image/mask dimension mismatch: {} vs {}",
            image_path.display(),
            mask_path.display()
        ));
    }

    let slots = ranked_slots(&image, &mask, layout);
    let phrases = split_replacement_text(text, slots.len());
    let slot_phrases: Vec<_> = slots
        .into_iter()
        .zip(phrases)
        .filter(|(slot, _)| slot_background_is_clear(&image, slot.bbox))
        .collect();
    if slot_phrases.is_empty() {
        if let Some(parent) = out_path.parent() {
            fs::create_dir_all(parent).map_err(|e| e.to_string())?;
        }
        image
            .save(out_path)
            .map_err(|e| format!("save {}: {e}", out_path.display()))?;
        return Ok(());
    }

    for (slot, phrase) in &slot_phrases {
        draw_phrase_in_slot(&mut image, slot, phrase, scale_override);
    }

    if let Some(parent) = out_path.parent() {
        fs::create_dir_all(parent).map_err(|e| e.to_string())?;
    }
    image
        .save(out_path)
        .map_err(|e| format!("save {}: {e}", out_path.display()))?;
    Ok(())
}

fn ranked_slots(image: &RgbaImage, mask: &GrayImage, layout: LayoutMode) -> Vec<TextSlot> {
    let mut slots = match layout {
        LayoutMode::Mask => text_slots(mask),
        LayoutMode::Surface => surface_slots(image, mask),
    };
    slots = slots
        .into_iter()
        .filter_map(|slot| erode_slot_to_clean_interior(image, slot))
        .collect();
    slots.sort_by_key(|slot| (slot.bbox[1], slot.bbox[0]));
    slots.retain(|slot| slot_background_is_clear(image, slot.bbox));
    slots
}

#[derive(Clone, Debug)]
struct RankedChoice {
    image: PathBuf,
    mask: PathBuf,
    stem: String,
    score: f32,
    slots: usize,
}

fn choose_ranked_random_image(
    images: &[PathBuf],
    mask_dir: &Path,
    args: &Args,
) -> Result<RankedChoice, String> {
    let text_units = semantic_text_units(&args.text);
    let mut choices = Vec::new();
    for image_path in images {
        let Some(stem) = image_path
            .file_name()
            .and_then(|name| name.to_str())
            .and_then(|name| name.strip_suffix(".cleared.png"))
        else {
            continue;
        };
        let mask_path = mask_dir.join(format!("{stem}.text-region-mask.png"));
        if !mask_path.exists() {
            continue;
        }
        let image = image::open(image_path)
            .map_err(|e| format!("image decode {}: {e}", image_path.display()))?
            .to_rgba8();
        let mask = image::open(&mask_path)
            .map_err(|e| format!("mask decode {}: {e}", mask_path.display()))?
            .to_luma8();
        if image.dimensions() != mask.dimensions() {
            continue;
        }
        let slots = ranked_slots(&image, &mask, args.layout);
        let score = topology_match_score(&text_units, &slots);
        if score > 0.0 {
            choices.push(RankedChoice {
                image: image_path.clone(),
                mask: mask_path,
                stem: stem.to_string(),
                score,
                slots: slots.len(),
            });
        }
    }
    if choices.is_empty() {
        return Err("no topology-ranked recomposition candidates found".to_string());
    }
    choices.sort_by(|a, b| {
        b.score
            .partial_cmp(&a.score)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.stem.cmp(&b.stem))
    });
    let best = choices[0].score;
    let top: Vec<_> = choices
        .into_iter()
        .take_while(|choice| choice.score >= best * 0.92)
        .collect();
    let index = pseudo_random_index(top.len());
    Ok(top[index].clone())
}

fn semantic_text_units(text: &str) -> Vec<String> {
    let pipe_units: Vec<_> = text
        .split('|')
        .map(str::trim)
        .filter(|unit| !unit.is_empty())
        .map(ToOwned::to_owned)
        .collect();
    if pipe_units.len() > 1 {
        return pipe_units;
    }
    let mut units = Vec::new();
    let mut current = String::new();
    for ch in text.chars() {
        current.push(ch);
        if matches!(ch, '.' | '!' | '?') {
            let trimmed = current.trim();
            if !trimmed.is_empty() {
                units.push(trimmed.to_string());
            }
            current.clear();
        }
    }
    let trimmed = current.trim();
    if !trimmed.is_empty() {
        units.push(trimmed.to_string());
    }
    if units.is_empty() {
        units.push(text.trim().to_string());
    }
    units
}

fn topology_match_score(units: &[String], slots: &[TextSlot]) -> f32 {
    if units.is_empty() || slots.is_empty() {
        return 0.0;
    }
    let unit_count = units.len() as i32;
    let slot_count = slots.len() as i32;
    let count_score = if unit_count == slot_count {
        1.0
    } else if unit_count == 1 && slot_count != 1 {
        0.18
    } else {
        (1.0 - (unit_count - slot_count).abs() as f32 * 0.28).clamp(0.0, 0.82)
    };
    let total_chars = units.iter().map(|unit| unit.chars().count()).sum::<usize>() as f32;
    let capacity = slots
        .iter()
        .map(|slot| {
            let [x0, y0, x1, y1] = slot.bbox;
            let w = x1.saturating_sub(x0).saturating_add(1) as f32;
            let h = y1.saturating_sub(y0).saturating_add(1) as f32;
            ((w / 4.0).floor() * (h / 6.0).floor()).max(1.0)
        })
        .sum::<f32>();
    let capacity_ratio = (capacity / total_chars.max(1.0)).min(1.0);
    let balance = slot_balance_score(slots);
    0.55 * count_score + 0.30 * capacity_ratio + 0.15 * balance
}

fn slot_balance_score(slots: &[TextSlot]) -> f32 {
    if slots.len() <= 1 {
        return 1.0;
    }
    let areas: Vec<f32> = slots.iter().map(|slot| slot.area as f32).collect();
    let mean = areas.iter().sum::<f32>() / areas.len() as f32;
    if mean <= 0.0 {
        return 0.0;
    }
    let deviation = areas.iter().map(|area| (area - mean).abs()).sum::<f32>() / areas.len() as f32;
    (1.0 - (deviation / mean).min(1.0)).clamp(0.0, 1.0)
}

fn pseudo_random_index(len: usize) -> usize {
    if len <= 1 {
        return 0;
    }
    let nanos = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_nanos() as usize)
        .unwrap_or(0);
    nanos % len
}

fn slot_background_is_clear(image: &RgbaImage, bbox: [u32; 4]) -> bool {
    let [x0, y0, x1, y1] = bbox;
    if x1 < x0 || y1 < y0 {
        return false;
    }
    let mut dark = 0_u32;
    let mut total = 0_u32;
    for y in y0..=y1.min(image.height().saturating_sub(1)) {
        for x in x0..=x1.min(image.width().saturating_sub(1)) {
            total = total.saturating_add(1);
            let [r, g, b, a] = image.get_pixel(x, y).0;
            if a == 0 {
                continue;
            }
            let luma = 0.2126 * r as f32 + 0.7152 * g as f32 + 0.0722 * b as f32;
            if luma <= 96.0 {
                dark = dark.saturating_add(1);
            }
        }
    }
    total > 0 && dark as f32 / total as f32 <= 0.08
}

fn erode_slot_to_clean_interior(image: &RgbaImage, slot: TextSlot) -> Option<TextSlot> {
    let [mut x0, mut y0, mut x1, mut y1] = slot.bbox;
    let mut changed = true;
    while changed && x1 > x0 + 6 && y1 > y0 + 6 {
        changed = false;
        let top_dirty = dark_fraction(image, x0, y0, x1, y0) > 0.04;
        let bottom_dirty = dark_fraction(image, x0, y1, x1, y1) > 0.04;
        let left_dirty = dark_fraction(image, x0, y0, x0, y1) > 0.04;
        let right_dirty = dark_fraction(image, x1, y0, x1, y1) > 0.04;
        if top_dirty {
            y0 = y0.saturating_add(1);
            changed = true;
        }
        if bottom_dirty && y1 > y0 {
            y1 = y1.saturating_sub(1);
            changed = true;
        }
        if left_dirty {
            x0 = x0.saturating_add(1);
            changed = true;
        }
        if right_dirty && x1 > x0 {
            x1 = x1.saturating_sub(1);
            changed = true;
        }
    }
    if x1 <= x0 + 5 || y1 <= y0 + 5 || !slot_background_is_clear(image, [x0, y0, x1, y1]) {
        return None;
    }
    Some(TextSlot {
        bbox: [x0, y0, x1, y1],
        area: slot.area,
    })
}

fn dark_fraction(image: &RgbaImage, x0: u32, y0: u32, x1: u32, y1: u32) -> f32 {
    if x1 < x0 || y1 < y0 {
        return 0.0;
    }
    let mut dark = 0_u32;
    let mut total = 0_u32;
    for y in y0..=y1.min(image.height().saturating_sub(1)) {
        for x in x0..=x1.min(image.width().saturating_sub(1)) {
            total = total.saturating_add(1);
            if is_dark_pixel(image.get_pixel(x, y)) {
                dark = dark.saturating_add(1);
            }
        }
    }
    if total == 0 {
        0.0
    } else {
        dark as f32 / total as f32
    }
}

fn is_dark_pixel(pixel: &Rgba<u8>) -> bool {
    let [r, g, b, a] = pixel.0;
    if a == 0 {
        return false;
    }
    let luma = 0.2126 * r as f32 + 0.7152 * g as f32 + 0.0722 * b as f32;
    luma <= 96.0
}

fn text_slots(mask: &GrayImage) -> Vec<TextSlot> {
    let width = mask.width() as usize;
    let height = mask.height() as usize;
    if width == 0 || height == 0 {
        return Vec::new();
    }
    let mut seen = vec![false; width * height];
    let mut slots = Vec::new();
    for y in 0..height {
        for x in 0..width {
            let index = y * width + x;
            if seen[index] || mask.get_pixel(x as u32, y as u32).0[0] == 0 {
                continue;
            }
            seen[index] = true;
            let mut queue = VecDeque::from([(x, y)]);
            let mut min_x = x;
            let mut max_x = x;
            let mut min_y = y;
            let mut max_y = y;
            let mut area = 0_u32;
            while let Some((cx, cy)) = queue.pop_front() {
                area = area.saturating_add(1);
                min_x = min_x.min(cx);
                max_x = max_x.max(cx);
                min_y = min_y.min(cy);
                max_y = max_y.max(cy);
                for (nx, ny) in neighbors4(cx, cy, width, height) {
                    let ni = ny * width + nx;
                    if seen[ni] || mask.get_pixel(nx as u32, ny as u32).0[0] == 0 {
                        continue;
                    }
                    seen[ni] = true;
                    queue.push_back((nx, ny));
                }
            }
            let bw = max_x - min_x + 1;
            let bh = max_y - min_y + 1;
            if area >= 12 && bw >= 3 && bh >= 3 {
                slots.push(TextSlot {
                    bbox: [min_x as u32, min_y as u32, max_x as u32, max_y as u32],
                    area,
                });
            }
        }
    }
    merge_line_slots(slots)
}

fn surface_slots(image: &RgbaImage, mask: &GrayImage) -> Vec<TextSlot> {
    let width = image.width() as usize;
    let height = image.height() as usize;
    if width == 0 || height == 0 {
        return Vec::new();
    }
    let anchors = text_slots(mask);
    let mut seen = vec![false; width * height];
    let mut slots = Vec::new();
    for y in 0..height {
        for x in 0..width {
            let index = y * width + x;
            if seen[index] || !is_recompose_surface_pixel(image.get_pixel(x as u32, y as u32)) {
                continue;
            }
            seen[index] = true;
            let mut queue = VecDeque::from([(x, y)]);
            let mut min_x = x;
            let mut max_x = x;
            let mut min_y = y;
            let mut max_y = y;
            let mut area = 0_u32;
            let mut touches_edge = false;
            let mut mask_hits = 0_u32;
            let mut mask_min_x = usize::MAX;
            let mut mask_max_x = 0_usize;
            let mut mask_min_y = usize::MAX;
            let mut mask_max_y = 0_usize;
            while let Some((cx, cy)) = queue.pop_front() {
                area = area.saturating_add(1);
                touches_edge =
                    touches_edge || cx == 0 || cy == 0 || cx + 1 == width || cy + 1 == height;
                min_x = min_x.min(cx);
                max_x = max_x.max(cx);
                min_y = min_y.min(cy);
                max_y = max_y.max(cy);
                if mask.get_pixel(cx as u32, cy as u32).0[0] > 0 {
                    mask_hits = mask_hits.saturating_add(1);
                    mask_min_x = mask_min_x.min(cx);
                    mask_max_x = mask_max_x.max(cx);
                    mask_min_y = mask_min_y.min(cy);
                    mask_max_y = mask_max_y.max(cy);
                }
                for (nx, ny) in neighbors4(cx, cy, width, height) {
                    let ni = ny * width + nx;
                    if seen[ni]
                        || !is_recompose_surface_pixel(image.get_pixel(nx as u32, ny as u32))
                    {
                        continue;
                    }
                    seen[ni] = true;
                    queue.push_back((nx, ny));
                }
            }
            let bw = max_x - min_x + 1;
            let bh = max_y - min_y + 1;
            if touches_edge || mask_hits == 0 || area < 120 || bw < 16 || bh < 12 {
                continue;
            }
            for anchor in anchors.iter().filter(|anchor| {
                bbox_overlap(
                    anchor.bbox,
                    [min_x as u32, min_y as u32, max_x as u32, max_y as u32],
                )
            }) {
                let [ax0, ay0, ax1, ay1] = anchor.bbox;
                let mask_w = ax1.saturating_sub(ax0).saturating_add(1);
                let mask_h = ay1.saturating_sub(ay0).saturating_add(1);
                let oversized_panel_surface = area > anchor.area.saturating_mul(4)
                    || bw as u32 > mask_w.saturating_mul(3)
                    || bh as u32 > mask_h.saturating_mul(3);
                if oversized_panel_surface {
                    continue;
                }
                let surface_pad_x = (bw as u32 / 10).clamp(3, 10);
                let surface_pad_y = (bh as u32 / 8).clamp(3, 10);
                let surface_x0 = (min_x as u32).saturating_add(surface_pad_x);
                let surface_y0 = (min_y as u32).saturating_add(surface_pad_y);
                let surface_x1 = (max_x as u32).saturating_sub(surface_pad_x);
                let surface_y1 = (max_y as u32).saturating_sub(surface_pad_y);
                let anchor_pad_x = (mask_w / 2).clamp(10, 56);
                let anchor_pad_y = (mask_h / 2).clamp(8, 36);
                let (x0, y0, x1, y1) = (
                    surface_x0.max(ax0.saturating_sub(anchor_pad_x)),
                    surface_y0.max(ay0.saturating_sub(anchor_pad_y)),
                    surface_x1.min(ax1.saturating_add(anchor_pad_x)),
                    surface_y1.min(ay1.saturating_add(anchor_pad_y)),
                );
                if x1 <= x0 || y1 <= y0 {
                    continue;
                }
                slots.push(TextSlot {
                    bbox: [x0, y0, x1, y1],
                    area: anchor.area,
                });
            }
        }
    }
    if slots.is_empty() {
        return contour_supported_slots(image, &anchors);
    }
    slots
}

fn bbox_overlap(a: [u32; 4], b: [u32; 4]) -> bool {
    a[0] <= b[2] && a[2] >= b[0] && a[1] <= b[3] && a[3] >= b[1]
}

fn contour_supported_slots(image: &RgbaImage, anchors: &[TextSlot]) -> Vec<TextSlot> {
    anchors
        .iter()
        .copied()
        .filter(|slot| has_multisided_contour_support(image, slot.bbox))
        .collect()
}

fn has_multisided_contour_support(image: &RgbaImage, bbox: [u32; 4]) -> bool {
    let width = image.width();
    let height = image.height();
    if width == 0 || height == 0 {
        return false;
    }
    let [x0, y0, x1, y1] = bbox;
    let bw = x1.saturating_sub(x0).saturating_add(1);
    let bh = y1.saturating_sub(y0).saturating_add(1);
    let search_x = (bw / 2).clamp(12, 48);
    let search_y = (bh / 2).clamp(10, 36);
    let sx0 = x0.saturating_sub(search_x);
    let sy0 = y0.saturating_sub(search_y);
    let sx1 = x1.saturating_add(search_x).min(width - 1);
    let sy1 = y1.saturating_add(search_y).min(height - 1);
    let top = count_dark_pixels(image, sx0, sy0, sx1, y0.saturating_sub(1)) >= 8;
    let bottom = count_dark_pixels(image, sx0, y1.saturating_add(1).min(height - 1), sx1, sy1) >= 8;
    let left = count_dark_pixels(image, sx0, sy0, x0.saturating_sub(1), sy1) >= 8;
    let right = count_dark_pixels(image, x1.saturating_add(1).min(width - 1), sy0, sx1, sy1) >= 8;
    [top, bottom, left, right]
        .into_iter()
        .filter(|supported| *supported)
        .count()
        >= 3
}

fn count_dark_pixels(image: &RgbaImage, x0: u32, y0: u32, x1: u32, y1: u32) -> u32 {
    if x1 < x0 || y1 < y0 {
        return 0;
    }
    let mut count = 0_u32;
    for y in y0..=y1 {
        for x in x0..=x1 {
            let [r, g, b, a] = image.get_pixel(x, y).0;
            if a == 0 {
                continue;
            }
            let luma = 0.2126 * r as f32 + 0.7152 * g as f32 + 0.0722 * b as f32;
            if luma <= 80.0 {
                count = count.saturating_add(1);
            }
        }
    }
    count
}

fn is_recompose_surface_pixel(pixel: &Rgba<u8>) -> bool {
    let [r, g, b, a] = pixel.0;
    if a == 0 {
        return false;
    }
    let luma = 0.2126 * r as f32 + 0.7152 * g as f32 + 0.0722 * b as f32;
    luma >= 215.0 && r.abs_diff(g) <= 18 && g.abs_diff(b) <= 18
}

fn merge_line_slots(mut slots: Vec<TextSlot>) -> Vec<TextSlot> {
    slots.sort_by_key(|slot| (slot.bbox[1], slot.bbox[0]));
    let mut rows: Vec<TextSlot> = Vec::new();
    'slot: for slot in slots {
        let height = slot.bbox[3].saturating_sub(slot.bbox[1]).saturating_add(1);
        for row in &mut rows {
            let row_height = row.bbox[3].saturating_sub(row.bbox[1]).saturating_add(1);
            let vertical_overlap = row.bbox[3]
                .min(slot.bbox[3])
                .saturating_sub(row.bbox[1].max(slot.bbox[1]));
            let close_x = slot.bbox[0] <= row.bbox[2].saturating_add(height.max(row_height) * 2);
            if vertical_overlap >= height.min(row_height) / 2 && close_x {
                row.bbox = [
                    row.bbox[0].min(slot.bbox[0]),
                    row.bbox[1].min(slot.bbox[1]),
                    row.bbox[2].max(slot.bbox[2]),
                    row.bbox[3].max(slot.bbox[3]),
                ];
                row.area = row.area.saturating_add(slot.area);
                continue 'slot;
            }
        }
        rows.push(slot);
    }
    rows
}

fn draw_phrase_in_slot(
    image: &mut RgbaImage,
    slot: &TextSlot,
    phrase: &str,
    scale_override: Option<u32>,
) {
    let [x0, y0, x1, y1] = slot.bbox;
    let slot_w = x1.saturating_sub(x0).saturating_add(1).max(1);
    let slot_h = y1.saturating_sub(y0).saturating_add(1).max(1);
    let max_scale = scale_override
        .unwrap_or_else(|| ((slot_h / 9).max(1)).min(3))
        .max(1)
        .min(6);
    let fit = fit_phrase_in_slot(phrase, slot_w, slot_h, max_scale);
    let char_w = fit.char_width();
    let line_h = fit.line_height();
    let lines = fit.lines;
    let total_h = (lines.len() as u32).saturating_mul(line_h);
    let start_y = y0 + slot_h.saturating_sub(total_h) / 2;
    for (line_index, line) in lines.iter().enumerate() {
        let line_w = (line.chars().count() as u32).saturating_mul(char_w);
        let start_x = x0 + slot_w.saturating_sub(line_w) / 2;
        draw_text_line(
            image,
            line,
            start_x,
            start_y + line_index as u32 * line_h,
            fit.font,
            fit.scale,
            Rgba([16, 16, 16, 255]),
        );
    }
}

#[derive(Clone, Debug)]
struct TextFit {
    font: BitmapFont,
    scale: u32,
    lines: Vec<String>,
}

impl TextFit {
    fn char_width(&self) -> u32 {
        self.font.char_width() * self.scale
    }

    fn line_height(&self) -> u32 {
        self.font.line_height() * self.scale
    }
}

#[derive(Clone, Copy, Debug)]
enum BitmapFont {
    Normal,
    Tiny,
}

impl BitmapFont {
    fn char_width(self) -> u32 {
        match self {
            BitmapFont::Normal => 6,
            BitmapFont::Tiny => 4,
        }
    }

    fn line_height(self) -> u32 {
        match self {
            BitmapFont::Normal => 8,
            BitmapFont::Tiny => 6,
        }
    }
}

fn fit_phrase_in_slot(phrase: &str, slot_w: u32, slot_h: u32, max_scale: u32) -> TextFit {
    for scale in (1..=max_scale).rev() {
        let char_w = BitmapFont::Normal.char_width() * scale;
        let line_h = BitmapFont::Normal.line_height() * scale;
        let pad_x = scale.max(1);
        let pad_y = scale.max(1);
        let max_chars = ((slot_w.saturating_sub(pad_x * 2)) / char_w).max(1) as usize;
        let max_lines = ((slot_h.saturating_sub(pad_y * 2)) / line_h).max(1) as usize;
        let (lines, complete) = wrap_phrase(phrase, max_chars, max_lines);
        if complete {
            return TextFit {
                font: BitmapFont::Normal,
                scale,
                lines,
            };
        }
    }
    let char_w = BitmapFont::Tiny.char_width();
    let line_h = BitmapFont::Tiny.line_height();
    let max_chars = (slot_w / char_w).max(1) as usize;
    let max_lines = (slot_h / line_h).max(1) as usize;
    let (lines, _) = wrap_phrase(phrase, max_chars, max_lines);
    TextFit {
        font: BitmapFont::Tiny,
        scale: 1,
        lines,
    }
}

fn split_replacement_text(text: &str, slots: usize) -> Vec<String> {
    let cleaned = text.split_whitespace().collect::<Vec<_>>().join(" ");
    if slots <= 1 || cleaned.contains('|') {
        let mut parts: Vec<String> = cleaned
            .split('|')
            .map(str::trim)
            .filter(|part| !part.is_empty())
            .map(ToOwned::to_owned)
            .collect();
        if parts.is_empty() {
            parts.push("hello".to_string());
        }
        while parts.len() < slots {
            let last = parts.last().cloned().unwrap_or_else(|| "hello".to_string());
            parts.push(last);
        }
        return parts;
    }

    let words: Vec<&str> = cleaned.split_whitespace().collect();
    if words.is_empty() {
        return vec!["hello".to_string(); slots];
    }
    let per_slot = words.len().div_ceil(slots).max(1);
    let mut out = Vec::new();
    for chunk in words.chunks(per_slot) {
        out.push(chunk.join(" "));
    }
    while out.len() < slots {
        out.push(words.last().copied().unwrap_or("hello").to_string());
    }
    out
}

fn wrap_phrase(text: &str, max_chars: usize, max_lines: usize) -> (Vec<String>, bool) {
    let mut lines = Vec::new();
    let mut current = String::new();
    let upper = text.to_ascii_uppercase();
    let words = wrap_units(&upper, max_chars);
    let mut consumed = 0_usize;
    for word in &words {
        let candidate_len = if current.is_empty() {
            word.len()
        } else {
            current.len() + 1 + word.len()
        };
        if candidate_len > max_chars && !current.is_empty() {
            lines.push(current);
            current = String::new();
            if lines.len() == max_lines {
                break;
            }
        }
        if !current.is_empty() {
            current.push(' ');
        }
        current.push_str(word);
        consumed += 1;
    }
    if !current.is_empty() && lines.len() < max_lines {
        lines.push(current);
    }
    if lines.is_empty() {
        lines.push(upper.chars().take(max_chars).collect());
    }
    (lines, consumed == words.len())
}

fn wrap_units(text: &str, max_chars: usize) -> Vec<String> {
    let max_chars = max_chars.max(1);
    let mut out = Vec::new();
    for word in text.split_whitespace() {
        let chars: Vec<char> = word.chars().collect();
        if chars.len() <= max_chars {
            out.push(word.to_string());
            continue;
        }
        for chunk in chars.chunks(max_chars) {
            out.push(chunk.iter().collect());
        }
    }
    out
}

fn draw_text_line(
    image: &mut RgbaImage,
    text: &str,
    x: u32,
    y: u32,
    font: BitmapFont,
    scale: u32,
    color: Rgba<u8>,
) {
    let mut cursor_x = x;
    for ch in text.chars() {
        draw_glyph(image, ch, cursor_x, y, font, scale, color);
        cursor_x = cursor_x.saturating_add(font.char_width() * scale);
    }
}

fn draw_glyph(
    image: &mut RgbaImage,
    ch: char,
    x: u32,
    y: u32,
    font: BitmapFont,
    scale: u32,
    color: Rgba<u8>,
) {
    let glyph: Vec<&'static str> = match font {
        BitmapFont::Normal => glyph(ch).to_vec(),
        BitmapFont::Tiny => tiny_glyph(ch).to_vec(),
    };
    for (row, bits) in glyph.iter().enumerate() {
        for (col, bit) in bits.chars().enumerate() {
            if bit != '1' {
                continue;
            }
            draw_cell(
                image,
                x + col as u32 * scale,
                y + row as u32 * scale,
                scale,
                color,
            );
        }
    }
}

fn draw_cell(image: &mut RgbaImage, x: u32, y: u32, scale: u32, color: Rgba<u8>) {
    for dy in 0..scale {
        for dx in 0..scale {
            let px = x + dx;
            let py = y + dy;
            if px < image.width() && py < image.height() {
                image.put_pixel(px, py, color);
            }
        }
    }
}

