fn collect_cleared_images(input: &Path) -> Result<Vec<PathBuf>, String> {
    let mut paths = Vec::new();
    for entry in fs::read_dir(input).map_err(|e| format!("read_dir {}: {e}", input.display()))? {
        let path = entry.map_err(|e| e.to_string())?.path();
        if path
            .file_name()
            .and_then(|name| name.to_str())
            .is_some_and(|name| name.ends_with(".cleared.png"))
        {
            paths.push(path);
        }
    }
    Ok(paths)
}

fn neighbors4(
    x: usize,
    y: usize,
    width: usize,
    height: usize,
) -> impl Iterator<Item = (usize, usize)> {
    let mut out = Vec::with_capacity(4);
    if x > 0 {
        out.push((x - 1, y));
    }
    if y > 0 {
        out.push((x, y - 1));
    }
    if x + 1 < width {
        out.push((x + 1, y));
    }
    if y + 1 < height {
        out.push((x, y + 1));
    }
    out.into_iter()
}

fn output_name(image: &Path) -> String {
    let stem = image
        .file_name()
        .and_then(|name| name.to_str())
        .unwrap_or("image.png")
        .strip_suffix(".cleared.png")
        .unwrap_or("image");
    format!("{stem}.recomposed.png")
}

#[derive(Debug)]
struct Args {
    image: PathBuf,
    mask: Option<PathBuf>,
    out_dir: PathBuf,
    text: String,
    scale: Option<u32>,
    limit: Option<usize>,
    layout: LayoutMode,
    random_ranked: bool,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum LayoutMode {
    Mask,
    Surface,
}

impl Args {
    fn parse(argv: Vec<String>) -> Result<Self, String> {
        let mut image = None;
        let mut mask = None;
        let mut out_dir = PathBuf::from("recomposed");
        let mut text = "TEXT AS TOPOLOGY".to_string();
        let mut scale = None;
        let mut limit = None;
        let mut layout = LayoutMode::Mask;
        let mut random_ranked = false;
        let mut iter = argv.iter();
        while let Some(token) = iter.next() {
            match token.as_str() {
                "--image" => image = Some(PathBuf::from(required(&mut iter, token)?)),
                "--mask" => mask = Some(PathBuf::from(required(&mut iter, token)?)),
                "--out" => out_dir = PathBuf::from(required(&mut iter, token)?),
                "--text" => text = required(&mut iter, token)?,
                "--scale" => {
                    scale = Some(
                        required(&mut iter, token)?
                            .parse::<u32>()
                            .map_err(|e| format!("invalid --scale: {e}"))?,
                    )
                }
                "--limit" => {
                    limit = Some(
                        required(&mut iter, token)?
                            .parse::<usize>()
                            .map_err(|e| format!("invalid --limit: {e}"))?,
                    )
                }
                "--layout" => {
                    layout = match required(&mut iter, token)?.as_str() {
                        "mask" => LayoutMode::Mask,
                        "surface" => LayoutMode::Surface,
                        other => {
                            return Err(format!(
                                "invalid --layout {other}: expected mask or surface"
                            ))
                        }
                    }
                }
                "--random-ranked" => {
                    random_ranked = true;
                }
                "-h" | "--help" => return Err(usage()),
                other => return Err(format!("unknown argument {other}\n{}", usage())),
            }
        }
        Ok(Self {
            image: image.ok_or_else(usage)?,
            mask,
            out_dir,
            text,
            scale,
            limit,
            layout,
            random_ranked,
        })
    }
}

fn required<'a>(iter: &mut std::slice::Iter<'a, String>, flag: &str) -> Result<String, String> {
    iter.next()
        .cloned()
        .ok_or_else(|| format!("missing value for {flag}"))
}

fn usage() -> String {
    "usage: why-text-recompose --image CLEARED_PNG_OR_DIR --mask MASK_PNG_OR_DIR --out DIR --text TEXT [--layout mask|surface] [--random-ranked] [--scale N] [--limit N]".to_string()
}
